  ('public-health-specialist-moex-01027', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '公共衛生師執行業務，不包含下列那一項？', '["社區與場域之醫療行為之執行與評估", "社區與場域之環境健康風險及方案之規劃、推動或評估", "社區與場域之疫病調查及防治方案之規劃、推動或評估", "社區與場域之民眾健康狀態調查及健康促進方案之規劃、推動或評估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
