  ('public-health-specialist-moex-01029', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '關於傳染病防治法所規定之隔離治療，下列敘述何者正確？', '["主管機關應先做成隔離治療通知書，公告周知大眾", "隔離前應經法院許可", "第一類傳染病病人應於指定隔離治療機構接受隔離治療", "施行隔離治療之費用，政府得補助低收入之民眾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01030', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '關於傳染病防治法對法定傳染病疫情調查之規定，下列敘述何者正確？', '["基於偵查不公開之原則，主管機關不得公布疫苗接種死亡之資料", "針對法定傳染病之病人是否接受檢驗，應尊重病人自主", "任何人發現疑似傳染病人時，應迅速通報當地警政機關", "政府機關因業務知悉傳染病或疑似傳染病病人之姓名、病歷及病史，不得洩漏"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01031', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '關於飲用水之管理，下列敘述何者正確？', '["供販賣之包裝或盛裝之飲用水，其水源之水質管理，依食品衛生管理法管理", "飲用水水質處理所使用之藥劑，得由各地方主管機關裁量", "因天災造成飲用水水源水質惡化時，自來水供水單位應加強飲用水水質檢驗，並透過報紙、電 視等方式，儘速通知民眾水質狀況及因應措施", "供販賣之包裝或盛裝之飲用水，其水質之查驗，依飲用水管理條例管理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01032', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '根據環境影響評估法，經行政院環境保護署審查認定對環境有重大影響之虞，應繼續進行第二階 段環境影響評估者，開發單位應辦理之事項，下列敘述何者錯誤？', '["將環境影響說明書分送有關機關", "將環境影響說明書於開發場所附近適當地點揭示1週", "於報紙刊登開發單位之名稱、開發場所、審查結論及環境影響說明書陳列或揭示地點", "於揭示期滿後，舉行公開說明會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01033', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '藥事法第102條第2項有關醫藥分業之規定，下列敘述何者錯誤？', '["醫藥分業制度可使藥師在調劑藥品過程中再次確認用藥之正確性，有利於保障病人用藥安全", "醫藥分業不應限制醫師之藥品調劑權，因將違反憲法第 15 條保障人民工作權之意旨，且對醫 師權利作不必要之限制而牴觸憲法第23條比例原則之規定", "醫師於中央或直轄市衛生主管機關公告無藥事人員執業之偏遠地區，得依自開處方，親自為藥 品之調劑", "醫師得因急迫醫療處置而自為藥品調劑，但急迫處置不應僅限於須立即使用藥品、或當場施與 針劑或口服藥劑之情況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01034', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列有關食品安全衛生規範之敘述何者正確？', '["我國食品安全衛生管理法僅管制食品及食品添加物，食品器具、容器與包裝因與食品本身無關， 故不在食品安全衛生管理法之規範範圍內", "上市、上櫃之食品業者，依法應設置實驗室，從事自主檢驗", "因基改食品是否具有健康風險尚未經科學證據證明，故食品包裝上並不須標示是否含基因改造 食品原料", "食品安全衛生主管機關不得進入製造、加工、調配、包裝、運送、貯存、販賣場所執行現場查 核及抽樣檢驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01035', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '下列有關菸害防制法之敘述，何者錯誤？', '["為保障言論自由，政府不得強制菸商在菸品容器上標示尼古丁與焦油含量", "我國室內場所並未全面禁菸，如晚上 9 點以後開始營業且 18 歲以上始能進入之酒吧，不在限 制範圍內", "菸品健康捐可用於全民健康保險之安全準備、罕見疾病醫療費用與癌症防治等用途", "電子煙或加熱菸等新興菸品可能非以菸草或其代用品為原料製成、組成非屬傳統菸品之電子器 材，或健康風險未經適當評估，形成菸害防制法之管制漏洞"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-01036', 'public-health-specialist', 'public-health-specialist-moex-110-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '學校衛生法有關學生健康管理制度之敘述，下列何者錯誤？', '["學校應定期辦理學生健康檢查", "學校應將學生健康檢查結果載入學生資料", "學校對學生健康檢查資料應予保密，不得併隨學籍轉移", "應教學需要，經學生家長同意，學校得例外提供學生健康檢查資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:42+00:00", "source_pdf_sha1": "5df59052b28e", "answer_pdf_sha1": "0d98a49df0f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
